class DistributedCacheService:
    def __init__(self, host_port_tuples, password=None, db=0, default_ttl_seconds=3600):
        """
        Initializes the DistributedCacheService with connections to multiple Redis nodes.

        :param host_port_tuples: A list of (host, port) tuples for Redis cluster nodes.
                                 e.g., [('redis-node-1.example.com', 6379), ('redis-node-2.example.com', 6379)]
        :param password: The password for Redis authentication. Defaults to None.
        :param db: The Redis database number to connect to. Defaults to 0.
        :param default_ttl_seconds: Default TTL for keys in seconds if not specified during set.
        """
        if not host_port_tuples:
            raise ValueError("host_port_tuples cannot be empty. At least one Redis node is required.")

        self.connections = []
        for host, port in host_port_tuples:
            try:
                # In a true Redis Cluster, redis-py-cluster would be used.
                # For multiple standalone Redis instances acting as a "cluster" for client-side sharding,
                # we'd connect to each. Here we're just connecting to multiple for robustness/failover demonstration.
                # If using Redis Cluster (official), redis.RedisCluster is the way.
                # This implementation assumes multiple standalone Redis instances or a simple
                # primary/replica setup where all nodes are reachable directly.
                r = redis.Redis(
                    host=host,
                    port=port,
                    password=password,
                    db=db,
                    decode_responses=True, # Decode responses to UTF-8 strings
                    socket_connect_timeout=5, # Timeout for establishing connection
                    socket_timeout=5 # Timeout for read/write operations
                )
                r.ping() # Test connection
                self.connections.append(r)
                print(f"Successfully connected to Redis at {host}:{port}")
            except redis.exceptions.ConnectionError as e:
                print(f"Warning: Could not connect to Redis at {host}:{port}. Error: {e}")
            except Exception as e:
                print(f"An unexpected error occurred connecting to Redis at {host}:{port}. Error: {e}")

        if not self.connections:
            raise ConnectionError("Failed to connect to any Redis node specified.")

        self.default_ttl_seconds = default_ttl_seconds
        self.current_connection_index = 0 # Simple round-robin for writes, or just use first for reads

    def _get_active_connection(self):
        """
        Gets an active Redis connection, trying multiple if the current one fails.
        Implements a simple round-robin retry for robustness.
        """
        num_connections = len(self.connections)
        for _ in range(num_connections):
            conn = self.connections[self.current_connection_index]
            try:
                conn.ping()
                return conn
            except (redis.exceptions.ConnectionError, redis.exceptions.TimeoutError):
                print(f"Connection to Redis at {conn.connection_pool.host}:{conn.connection_pool.port} lost. Trying next...")
                self.current_connection_index = (self.current_connection_index + 1) % num_connections
        raise ConnectionError("All Redis connections failed.")

    def _get_connection_for_read(self):
        """
        For reads, can pick any active connection. Could be optimized for master/replica awareness.
        For simplicity, uses the same robust connection retrieval as writes.
        """
        return self._get_active_connection()

    def _get_connection_for_write(self):
        """
        For writes, ensures we get a working connection.
        If using a true cluster, writes are sharded automatically.
        Here, it just picks the next active connection in a round-robin fashion for simple load balancing/failover.
        """
        self.current_connection_index = (self.current_connection_index + 1) % len(self.connections)
        return self._get_active_connection()

    def set_sensitive_data(self, key_prefix, user_id, data_type, data, ttl_seconds=None):
        """
        Stores sensitive data in Redis with a generated key and an expiration.

        :param key_prefix: A prefix for the key (e.g., 'session', 'api_key').
        :param user_id: The ID of the user associated with the data.
        :param data_type: A descriptor for the data (e.g., 'token', 'secret').
        :param data: The sensitive data to store (e.g., session token, API key string).
        :param ttl_seconds: Time-to-live for the key in seconds. Uses default if None.
        :return: The full key under which the data was stored, or None on failure.
        """
        if not key_prefix or not user_id or not data_type or not data:
            print("Error: All key components and data must be provided.")
            return None

        # Create a unique key for the sensitive data
        # Example key: 'session:user:123:token:abcdef123'
        full_key = f"{key_prefix}:user:{user_id}:{data_type}:{uuid.uuid4().hex}"
        ttl = ttl_seconds if ttl_seconds is not None else self.default_ttl_seconds

        try:
            conn = self._get_connection_for_write()
            # Store data as a JSON string to handle various data types (though often it's just a string)
            # Use JSON for future flexibility, e.g., if you store { "token": "...", "expires_at": "..." }
            stored_data = json.dumps({"data": data, "created_at": datetime.datetime.now().isoformat()})
            conn.setex(full_key, ttl, stored_data)
            print(f"Stored sensitive data for user '{user_id}' under key '{full_key}' with TTL {ttl}s.")
            return full_key
        except ConnectionError as e:
            print(f"Failed to store data due to connection error: {e}")
        except redis.exceptions.RedisError as e:
            print(f"Redis error during set_sensitive_data: {e}")
        except Exception as e:
            print(f"An unexpected error occurred during set_sensitive_data: {e}")
        return None

    def get_sensitive_data(self, full_key):
        """
        Retrieves sensitive data from Redis.

        :param full_key: The exact key under which the data was stored.
        :return: The stored sensitive data (string), or None if not found or on error.
        """
        if not full_key:
            return None

        try:
            conn = self._get_connection_for_read()
            stored_json = conn.get(full_key)
            if stored_json:
                data_obj = json.loads(stored_json)
                print(f"Retrieved sensitive data for key '{full_key}'.")
                return data_obj.get("data")
            else:
                print(f"Key '{full_key}' not found or expired.")
                return None
        except ConnectionError as e:
            print(f"Failed to retrieve data due to connection error: {e}")
        except redis.exceptions.RedisError as e:
            print(f"Redis error during get_sensitive_data: {e}")
        except json.JSONDecodeError as e:
            print(f"Error decoding JSON for key '{full_key}': {e}")
        except Exception as e:
            print(f"An unexpected error occurred during get_sensitive_data: {e}")
        return None

    def delete_sensitive_data(self, full_key):
        """
        Deletes sensitive data from Redis.

        :param full_key: The exact key of the data to delete.
        :return: True if the key was deleted, False otherwise (e.g., key not found or error).
        """
        if not full_key:
            return False

        try:
            conn = self._get_connection_for_write()
            deleted_count = conn.delete(full_key)
            if deleted_count > 0:
                print(f"Deleted sensitive data for key '{full_key}'.")
                return True
            else:
                print(f"Key '{full_key}' not found for deletion.")
                return False
        except ConnectionError as e:
            print(f"Failed to delete data due to connection error: {e}")
        except redis.exceptions.RedisError as e:
            print(f"Redis error during delete_sensitive_data: {e}")
        except Exception as e:
            print(f"An unexpected error occurred during delete_sensitive_data: {e}")
        return False

    def close(self):
        """
        Closes all Redis connections in the pool.
        Note: redis-py connection pools handle connections automatically.
        This is more for explicit shutdown if needed, or if not using connection pools.
        For persistent services, you generally leave connections open.
        """
        for i, conn in enumerate(self.connections):
            try:
                conn.connection_pool.disconnect()
                print(f"Disconnected from Redis connection {i}.")
            except Exception as e:
                print(f"Error disconnecting from Redis connection {i}: {e}")

